SELECT warheads, warheads_decommissioned
FROM nuclear_stockpiles
WHERE warheads > 100;

SELECT SUM(warheads) AS total_warheads
FROM nuclear_stockpiles
WHERE country_id = 1;

SELECT country_id, SUM(warheads) AS total_warheads
FROM nuclear_stockpiles
GROUP BY country_id;

SELECT warhead_name, range
FROM warhead_types
ORDER BY range DESC;

SELECT DISTINCT analyst_name
FROM analysts
WHERE analyst_id IN (
    SELECT DISTINCT analyst_id
    FROM access_logs
);

SELECT warheads
FROM nuclear_stockpiles
WHERE stockpile_id = 1;

SELECT COUNT(*) 
FROM warhead_types 
WHERE payload_capacity > 500;
